import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { supabase } from '../lib/supabase';
import { Users, Database, ShieldAlert, Terminal, Trash2, Edit, Loader, Plus, X, Save, Lock, Mail, Building, ToggleLeft, ToggleRight } from 'lucide-react';

export const Admin: React.FC = () => {
  const { t } = useLanguage();
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    role: 'CLIENT',
    business_name: '',
    subscriptions: {
        sos_business: false
    }
  });

  const fetchUsers = async () => {
    setLoading(true);
    const { data } = await supabase.from('app_users').select('*').order('id', { ascending: true });
    if (data) setUsers(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  const handleOpenModal = (user?: any) => {
    if (user) {
        setEditingId(user.id);

        // Safety check: parse if subscriptions is a string (rare DB edge case) or ensure it's an object
        let userSubs = user.subscriptions;
        if (typeof userSubs === 'string') {
            try { userSubs = JSON.parse(userSubs); } catch(e) { console.error("Error parsing subs", e); }
        }

        setFormData({
            email: user.email,
            password: user.password,
            role: user.role,
            business_name: user.business_name || '',
            subscriptions: userSubs || { sos_business: false }
        });
    } else {
        setEditingId(null);
        setFormData({
            email: '',
            password: '',
            role: 'CLIENT',
            business_name: '',
            subscriptions: { sos_business: false }
        });
    }
    setIsModalOpen(true);
  };

  const handleDelete = async (id: number) => {
    if (window.confirm(t.admin.actions.confirmDelete)) {
        await supabase.from('app_users').delete().eq('id', id);
        fetchUsers();
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
        if (editingId) {
            // Update
            await supabase.from('app_users').update(formData).eq('id', editingId);
        } else {
            // Create
            await supabase.from('app_users').insert([formData]);
        }
        setIsModalOpen(false);
        fetchUsers();
    } catch (error) {
        console.error("Error saving user:", error);
        alert("Error saving user. Check console.");
    }
  };

  const toggleSubscription = (key: string) => {
      setFormData(prev => {
          // Create a safe copy of existing subscriptions, defaulting to empty object if null
          const currentSubs = prev.subscriptions ? { ...prev.subscriptions } : {};

          // Explicitly get current boolean value
          // @ts-ignore
          const currentValue = !!currentSubs[key];

          return {
              ...prev,
              subscriptions: {
                  ...currentSubs,
                  [key]: !currentValue
              }
          };
      });
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12 relative">
      <div className="flex items-center gap-4 mb-10 border-b border-neon-red/30 pb-6">
        <div className="p-3 bg-neon-red/10 border border-neon-red/30 rounded">
             <ShieldAlert className="text-neon-red" size={32} />
        </div>
        <div>
            <h1 className="text-3xl font-tech font-bold text-white uppercase tracking-wider">{t.admin.title}</h1>
            <p className="text-neon-red font-mono text-xs">RESTRICTED AREA // LEVEL 5 CLEARANCE</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
         <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-green/50 transition-colors">
            <div>
                <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.users}</div>
                <div className="text-3xl font-tech text-white">{users.length}</div>
            </div>
            <Users className="text-neon-green opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
         </div>
         <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-cyan/50 transition-colors">
            <div>
                <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.revenue}</div>
                <div className="text-3xl font-tech text-white">₪124k</div>
            </div>
            <Database className="text-neon-cyan opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
         </div>
         <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-red/50 transition-colors">
            <div>
                <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.errors}</div>
