import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { supabase } from '../lib/supabase';
import { Users, Database, ShieldAlert, Terminal, Trash2, Edit, Loader, Plus, X, Save, Lock, Mail, Building, ToggleLeft, ToggleRight } from 'lucide-react';

interface AdminFormData {
  email: string;
  password: string;
  role: string;
  business_name: string;
  subscriptions: {
    [key: string]: any;
  };
}

export const Admin: React.FC = () => {
  const { t } = useLanguage();
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState<AdminFormData>({
    email: '',
    password: '',
    role: 'CLIENT',
    business_name: '',
    subscriptions: {
        sos_business: false
    }
  });

  const fetchUsers = async () => {
    setLoading(true);
    const { data, error } = await supabase.from('app_users').select('*').order('id', { ascending: true });
    if (error) console.error("Error fetching users:", error);
    if (data) setUsers(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  const handleOpenModal = (user?: any) => {
    if (user) {
        setEditingId(user.id);

        // Safety check: parse if subscriptions is a string (rare DB edge case) or ensure it's an object
        let userSubs = user.subscriptions;
        if (typeof userSubs === 'string') {
            try { userSubs = JSON.parse(userSubs); } catch(e) { console.error("Error parsing subs", e); }
        }

        // Ensure defaults if null
        if (!userSubs) userSubs = { sos_business: false };

        setFormData({
            email: user.email,
            password: user.password,
            role: user.role,
            business_name: user.business_name || '',
            subscriptions: userSubs
        });
    } else {
        setEditingId(null);
        setFormData({
            email: '',
            password: '',
            role: 'CLIENT',
            business_name: '',
            subscriptions: { sos_business: false }
        });
    }
    setIsModalOpen(true);
  };

  const handleDelete = async (id: number) => {
    if (window.confirm(t.admin.actions.confirmDelete)) {
        const { error } = await supabase.from('app_users').delete().eq('id', id);
        if (error) {
            alert("Failed to delete: " + error.message);
        } else {
            fetchUsers();
        }
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
        const payload = {
            email: formData.email,
            password: formData.password,
            role: formData.role,
            business_name: formData.business_name,
            subscriptions: formData.subscriptions
        };

        let result;
        if (editingId) {
            // Update
            result = await supabase
                .from('app_users')
                .update(payload)
                .eq('id', editingId)
                .select();
        } else {
            // Create
            result = await supabase
                .from('app_users')
                .insert([payload])
                .select();
        }

        if (result.error) {
            throw result.error;
        }

        setIsModalOpen(false);
        // Add a small delay to ensure DB propagation if needed, though usually not required with .select()
        fetchUsers();
    } catch (error: any) {
        console.error("Error saving user:", error);
        alert(`Error saving user: ${error.message || 'Unknown error'}`);
    }
  };

  const toggleSubscription = (key: string) => {
      setFormData(prev => {
          // Create a safe copy of existing subscriptions
          const currentSubs = prev.subscriptions ? { ...prev.subscriptions } : {};

          // Explicitly get current boolean value
          const currentValue = !!currentSubs[key];

          return {
              ...prev,
              subscriptions: {
                  ...currentSubs,
                  [key]: !currentValue
              }
          };
      });
  };

