import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { supabase } from '../lib/supabase';
import { Users, Database, ShieldAlert, Terminal, Trash2, Edit, Loader, Plus, X, Save, Lock, Mail, Building, ToggleLeft, ToggleRight, AlertTriangle } from 'lucide-react';

interface AdminFormData {
  email: string;
  password: string;
  role: string;
  business_name: string;
  subscriptions: {
    [key: string]: any;
  };
}

export const Admin: React.FC = () => {
  const { t } = useLanguage();
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New Message/Error Modal State
  const [messageModal, setMessageModal] = useState({ 
    isOpen: false, 
    title: '', 
    text: '', 
    isError: false 
  });

  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState<AdminFormData>({
    email: '',
    password: '',
    role: 'CLIENT',
    business_name: '',
    subscriptions: {
        sos_business: false
    }
  });

  const fetchUsers = async () => {
    setLoading(true);
    const { data, error } = await supabase.from('app_users').select('*').order('id', { ascending: true });
    if (error) console.error("Error fetching users:", error);
    if (data) setUsers(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  // Helper to show custom modal instead of alert
  const showMessage = (title: string, text: string, isError = true) => {
    setMessageModal({ isOpen: true, title, text, isError });
  };

  const closeMessage = () => {
    setMessageModal(prev => ({ ...prev, isOpen: false }));
  };

  const handleOpenModal = (user?: any) => {
    if (user) {
        setEditingId(user.id);

        let userSubs = user.subscriptions;
        if (typeof userSubs === 'string') {
            try { userSubs = JSON.parse(userSubs); } catch(e) { console.error("Error parsing subs", e); }
        }

        if (!userSubs) userSubs = { sos_business: false };

        setFormData({
            email: user.email,
            password: user.password,
            role: user.role,
            business_name: user.business_name || '',
            subscriptions: userSubs
        });
    } else {
        setEditingId(null);
        setFormData({
            email: '',
            password: '',
            role: 'CLIENT',
            business_name: '',
            subscriptions: { sos_business: false }
        });
    }
    setIsModalOpen(true);
  };

  const handleDelete = async (id: number) => {
    if (window.confirm(t.admin.actions.confirmDelete)) {
        const { error } = await supabase.from('app_users').delete().eq('id', id);
        if (error) {
            showMessage("DELETE ERROR", error.message, true);
        } else {
            fetchUsers();
        }
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();

    // Base payload (fields we are sure exist)
    const basePayload = {
        email: formData.email,
        password: formData.password,
        role: formData.role,
        business_name: formData.business_name,
    };

    // Full payload including subscriptions
    const fullPayload = {
        ...basePayload,
        subscriptions: formData.subscriptions
    };

    try {
        let result;
        if (editingId) {
            // Update
            result = await supabase
                .from('app_users')
                .update(fullPayload)
                .eq('id', editingId)
                .select();
        } else {
            // Create
            result = await supabase
                .from('app_users')
                .insert([fullPayload])
                .select();
        }

        if (result.error) throw result.error;

        setIsModalOpen(false);
        fetchUsers();
        // showMessage("SUCCESS", "User saved successfully", false); // Optional success msg

    } catch (error: any) {
        console.error("Error saving user:", error);

        const errorMsg = error.message || '';

        // Intelligent Fallback:
        // If the error is about the missing 'subscriptions' column, retry saving ONLY the base fields.
        if (errorMsg.includes('subscriptions') && (errorMsg.includes('column') || errorMsg.includes('schema') || error.code === 'PGRST204')) {
            try {
                let retryResult;
                if (editingId) {
                    retryResult = await supabase.from('app_users').update(basePayload).eq('id', editingId).select();
                } else {
                    retryResult = await supabase.from('app_users').insert([basePayload]).select();
                }

                if (retryResult.error) throw retryResult.error;

                setIsModalOpen(false);
                fetchUsers();

                // Show a warning modal explaining what happened
                showMessage(
                    "PARTIAL SAVE", 
                    "User saved, but subscriptions failed because the 'subscriptions' column is missing in the database. Please add a JSONB column named 'subscriptions' to 'app_users'.", 
                    true
                );
                return;

            } catch (retryError: any) {
                 showMessage("SAVE ERROR", retryError.message || 'Retry failed', true);
                 return;
            }
        }

        showMessage("SAVE ERROR", errorMsg || 'Unknown error occurred', true);
    }
  };

  const toggleSubscription = (key: string) => {
      setFormData(prev => {
          const currentSubs = prev.subscriptions ? { ...prev.subscriptions } : {};
          const currentValue = !!currentSubs[key];
          return {
              ...prev,
              subscriptions: {
                  ...currentSubs,
                  [key]: !currentValue
              }
          };
      });
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12 relative">
      <div className="flex items-center gap-4 mb-10 border-b border-neon-red/30 pb-6">
        <div className="p-3 bg-neon-red/10 border border-neon-red/30 rounded">
             <ShieldAlert className="text-neon-red" size={32} />
        </div>
        <div>
            <h1 className="text-3xl font-tech font-bold text-white uppercase tracking-wider">{t.admin.title}</h1>
            <p className="text-neon-red font-mono text-xs">RESTRICTED AREA // LEVEL 5 CLEARANCE</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
         <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-green/50 transition-colors">
            <div>
                <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.users}</div>
                <div className="text-3xl font-tech text-white">{users.length}</div>
            </div>
            <Users className="text-neon-green opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
         </div>
         <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-cyan/50 transition-colors">
            <div>
                <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.revenue}</div>
                <div className="text-3xl font-tech text-white">₪124k</div>
            </div>
            <Database className="text-neon-cyan opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
         </div>
         <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-red/50 transition-colors">
            <div>
                <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.errors}</div>
                <div className="text-3xl font-tech text-white">0</div>
            </div>
            <Terminal className="text-neon-red opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
         </div>
      </div>

      {/* Users Table */}
      <div className="bg-bunker-900 border border-white/10 clip-corner relative">
         <div className="p-6 border-b border-white/10 flex justify-between items-center">
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Users size={20} className="text-slate-400"/>
                {t.admin.users}
            </h2>
            <div className="flex items-center gap-4">
                <div className="text-xs font-mono text-slate-500 hidden md:block">DB_CONNECTION: {loading ? 'FETCHING...' : 'ESTABLISHED'}</div>
                <button 
                    onClick={() => handleOpenModal()} 
                    className="flex items-center gap-2 bg-neon-green/10 text-neon-green border border-neon-green/30 px-4 py-2 text-xs font-mono font-bold uppercase hover:bg-neon-green hover:text-bunker-950 transition-all"
                >
                    <Plus size={14} />
                    {t.admin.actions.addUser}
                </button>
            </div>
         </div>
         <div className="overflow-x-auto">
            {loading ? (
                 <div className="p-12 flex justify-center text-neon-green animate-pulse"><Loader /></div>
            ) : (
                <table className="w-full text-left">
                    <thead className="bg-bunker-950 text-slate-500 font-mono text-xs uppercase">
                        <tr>
                            <th className="p-4">{t.admin.table.email}</th>
                            <th className="p-4">{t.admin.table.role}</th>
                            <th className="p-4">Business</th>
                            <th className="p-4">Subs</th>
                            <th className="p-4 text-right">{t.admin.table.actions}</th>
                        </tr>
                    </thead>
                    <tbody className="text-sm font-mono">
                        {users.map((user) => (
                            <tr key={user.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                                <td className="p-4 text-white font-bold">{user.email}</td>
                                <td className="p-4">
                                    <span className={`px-2 py-0.5 text-[10px] border rounded ${
                                        user.role === 'ADMIN' ? 'text-neon-red border-neon-red/30 bg-neon-red/10' : 'text-neon-cyan border-neon-cyan/30 bg-neon-cyan/10'
                                    }`}>
                                        {user.role}
                                    </span>
                                </td>
                                <td className="p-4 text-slate-400">
                                    {user.business_name}
                                </td>
                                <td className="p-4 text-slate-400 text-xs">
                                    {user.subscriptions?.sos_business && (
                                        <span className="text-neon-green border border-neon-green/30 px-1 rounded bg-neon-green/10">SOS</span>
                                    )}
                                </td>
                                <td className="p-4 flex justify-end gap-2">
                                    <button 
                                        onClick={() => handleOpenModal(user)}
                                        className="p-2 text-slate-400 hover:text-white hover:bg-white/10 rounded"
                                        title={t.admin.actions.editUser}
                                    >
                                        <Edit size={14} />
                                    </button>
                                    <button 
                                        onClick={() => handleDelete(user.id)}
                                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-500/10 rounded"
                                        title={t.admin.actions.deleteUser}
                                    >
                                        <Trash2 size={14} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            )}
         </div>
      </div>

      {/* Edit/Add Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-bunker-950/80 backdrop-blur-sm overflow-y-auto">
            <div className="bg-bunker-900 border border-white/20 w-full max-w-md clip-corner shadow-2xl relative animate-fade-in-up">
                <div className="p-6 border-b border-white/10 flex justify-between items-center">
                    <h3 className="text-xl font-tech font-bold text-white">
                        {editingId ? t.admin.actions.editUser : t.admin.actions.addUser}
                    </h3>
                    <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-white">
                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSave} className="p-6 space-y-4">
                    <div>
                        <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.auth.email}</label>
                        <div className="relative">
                            <Mail className="absolute left-3 top-3 text-slate-500" size={16} />
                            <input 
                                type="email" 
                                required
                                value={formData.email}
                                onChange={e => setFormData({...formData, email: e.target.value})}
                                className="w-full bg-bunker-950 border border-white/10 pl-10 pr-4 py-3 text-white focus:border-neon-green outline-none"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.auth.password}</label>
                        <div className="relative">
                            <Lock className="absolute left-3 top-3 text-slate-500" size={16} />
                            <input 
                                type="text" 
                                required
                                value={formData.password}
                                onChange={e => setFormData({...formData, password: e.target.value})}
                                className="w-full bg-bunker-950 border border-white/10 pl-10 pr-4 py-3 text-white focus:border-neon-green outline-none font-mono"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.profile.form.name}</label>
                        <div className="relative">
                            <Building className="absolute left-3 top-3 text-slate-500" size={16} />
                            <input 
                                type="text" 
                                value={formData.business_name}
                                onChange={e => setFormData({...formData, business_name: e.target.value})}
                                className="w-full bg-bunker-950 border border-white/10 pl-10 pr-4 py-3 text-white focus:border-neon-green outline-none"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.admin.table.role}</label>
                        <select 
                            value={formData.role}
                            onChange={e => setFormData({...formData, role: e.target.value})}
                            className="w-full bg-bunker-950 border border-white/10 px-4 py-3 text-white focus:border-neon-green outline-none"
                        >
                            <option value="CLIENT">CLIENT</option>
                            <option value="ADMIN">ADMIN</option>
                            <option value="OPERATOR">OPERATOR</option>
                        </select>
                    </div>

                    {/* Subscriptions Section */}
                    <div className="pt-4 border-t border-white/10">
                        <label className="block text-xs font-mono text-neon-green mb-3 uppercase tracking-widest">{t.admin.subs.title}</label>
                        <div className="space-y-3">
                            <div 
                                onClick={(e) => {
                                    e.preventDefault();
                                    toggleSubscription('sos_business');
                                }}
                                className={`flex items-center justify-between p-3 border cursor-pointer transition-all select-none ${
                                    formData.subscriptions?.sos_business 
                                    ? 'bg-neon-green/10 border-neon-green/50' 
                                    : 'bg-bunker-900 border-white/10 hover:border-white/30'
                                }`}
                            >
                                <span className={`text-sm font-bold ${
                                    formData.subscriptions?.sos_business ? 'text-white' : 'text-slate-400'
                                }`}>{t.admin.subs.sos_business}</span>

                                { formData.subscriptions?.sos_business 
                                  ? <ToggleRight size={24} className="text-neon-green" />
                                  : <ToggleLeft size={24} className="text-slate-600" />
                                }
                            </div>
                        </div>
                    </div>

                    <div className="flex gap-3 pt-4">
                        <button 
                            type="button" 
                            onClick={() => setIsModalOpen(false)}
                            className="flex-1 py-3 border border-white/10 text-slate-400 hover:text-white font-mono uppercase text-xs font-bold"
                        >
                            {t.admin.actions.cancel}
                        </button>
                        <button 
                            type="submit" 
                            className="flex-1 py-3 bg-neon-green text-bunker-950 font-mono uppercase text-xs font-bold hover:bg-white transition-colors flex items-center justify-center gap-2"
                        >
                            <Save size={14} />
                            {t.admin.actions.save}
                        </button>
                    </div>
                </form>
            </div>
        </div>
      )}

      {/* Message Modal (Replacement for Alert) */}
      {messageModal.isOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
             <div className={`bg-bunker-900 border ${messageModal.isError ? 'border-red-500/50' : 'border-neon-green/50'} p-8 max-w-sm w-full shadow-[0_0_50px_rgba(0,0,0,0.5)] clip-corner relative animate-fade-in-up`}>
                 <div className="flex items-start gap-4 mb-6">
                    <div className={`p-3 border rounded-full shrink-0 ${messageModal.isError ? 'bg-red-500/10 border-red-500/30 text-red-500' : 'bg-neon-green/10 border-neon-green/30 text-neon-green'}`}>
                        <AlertTriangle size={24} />
                    </div>
                    <div>
                        <h3 className={`text-xl font-tech font-bold uppercase mb-2 ${messageModal.isError ? 'text-red-500' : 'text-neon-green'}`}>
                            {messageModal.title}
                        </h3>
                        <p className="text-slate-300 font-mono text-sm leading-relaxed">
                            {messageModal.text}
                        </p>
                    </div>
                 </div>

                 <button 
                    onClick={closeMessage} 
                    className={`w-full py-3 font-bold uppercase tracking-widest text-xs border transition-all ${
                        messageModal.isError 
                        ? 'bg-red-500 text-white border-red-500 hover:bg-white hover:text-red-500' 
                        : 'bg-neon-green text-bunker-950 border-neon-green hover:bg-white'
                    }`}
                 >
                    ACKNOWLEDGE
                 </button>
             </div>
        </div>
      )}

    </div>
  );
};

-- Вставьте этот код в SQL Editor в панели управления Supabase и нажмите RUN

-- 1. Добавляем колонку subscriptions (тип JSONB, по умолчанию пустой объект)
ALTER TABLE app_users 
ADD COLUMN IF NOT EXISTS subscriptions jsonb DEFAULT '{}'::jsonb;

-- 2. Обновляем существующие записи, у которых эта колонка пустая (на всякий случай)
UPDATE app_users 
SET subscriptions = '{}'::jsonb 
WHERE subscriptions IS NULL;

-- 3. (Опционально) Проверяем, что колонка добавилась
SELECT * FROM app_users LIMIT 1;
